  class RevenueComponent {
    constructor(revenueService, fb) {
      this.revenueService = revenueService;
      this.fb = fb;
      this.revenueItems = [];
      this.filteredItems = [];
      this.showForm = false;
      this.editingItem = null;
      this.searchTerm = '';
      this.loading = false;
      this.error = null;
      // Date filtering
      this.selectedYear = new Date().getFullYear();
      this.selectedMonth = new Date().getMonth();
      this.viewMode = 'all';
      this.availableYears = [];
      this.availableMonths = ['January', 'February', 'March', 'April', 'May', 'June', 'July', 'August', 'September', 'October', 'November', 'December'];
      this.revenueForm = this.fb.group({
        date: ['', Validators.required],
        source: ['', Validators.required],
        amount: ['', [Validators.required, Validators.min(0)]],
        description: ['']
      });
    }
    ngOnInit() {
      this.loadRevenue();
      this.generateAvailableYears();
    }
    generateAvailableYears() {
      const currentYear = new Date().getFullYear();
      this.availableYears = [];
      for (let year = currentYear - 5; year <= currentYear + 1; year++) {
        this.availableYears.push(year);
      }
    }
    loadRevenue() {
      this.loading = true;
      this.error = null;
      this.revenueService.getAllRevenue().subscribe({
        next: data => {
          this.revenueItems = data;
          this.applyFilters();
          this.loading = false;
        },
        error: error => {
          this.error = 'Failed to load revenue data';
          this.loading = false;
          console.error('Error loading revenue:', error);
        }
      });
    }
    applyFilters() {
      let filtered = [...this.revenueItems];
      // Apply search filter
      if (this.searchTerm.trim()) {
        const term = this.searchTerm.toLowerCase();
        filtered = filtered.filter(item => item.source.toLowerCase().includes(term) || item.description?.toLowerCase().includes(term) || item.amount.toString().includes(term));
      }
      // Apply date filters
      if (this.viewMode === 'yearly') {
        filtered = filtered.filter(item => {
          const itemDate = new Date(item.date);
          return itemDate.getFullYear() === this.selectedYear;
        });
      } else if (this.viewMode === 'monthly') {
        filtered = filtered.filter(item => {
          const itemDate = new Date(item.date);
          return itemDate.getFullYear() === this.selectedYear && itemDate.getMonth() === this.selectedMonth;
        });
      } else if (this.viewMode === 'daily') {
        const today = new Date();
        filtered = filtered.filter(item => {
          const itemDate = new Date(item.date);
          return itemDate.toDateString() === today.toDateString();
        });
      }
      this.filteredItems = filtered;
    }
    onSearch() {
      this.applyFilters();
    }
    onViewModeChange() {
      this.applyFilters();
    }
    onYearChange() {
      this.applyFilters();
    }
    onMonthChange() {
      this.applyFilters();
    }
    openAddForm() {
      this.editingItem = null;
      this.revenueForm.reset();
      this.revenueForm.patchValue({
        date: new Date().toISOString().split('T')[0] // Today's date
      });

      this.showForm = true;
    }
    editItem(item) {
      this.editingItem = item;
      this.revenueForm.patchValue({
        date: item.date,
        source: item.source,
        amount: item.amount,
        description: item.description || ''
      });
      this.showForm = true;
    }
    cancelForm() {
      this.showForm = false;
      this.editingItem = null;
      this.revenueForm.reset();
    }
    onSubmit() {
      if (this.revenueForm.valid) {
        const formValue = this.revenueForm.value;
        if (this.editingItem) {
          // Update existing item
          this.revenueService.updateRevenue(this.editingItem.id, formValue).subscribe({
            next: () => {
              this.loadRevenue();
              this.cancelForm();
            },
            error: error => {
              this.error = 'Failed to update revenue item';
              console.error('Error updating revenue:', error);
            }
          });
        } else {
          // Create new item
          this.revenueService.createRevenue(formValue).subscribe({
            next: () => {
              this.loadRevenue();
              this.cancelForm();
            },
            error: error => {
              this.error = 'Failed to create revenue item';
              console.error('Error creating revenue:', error);
            }
          });
        }
      } else {
        this.revenueForm.markAllAsTouched();
      }
    }
    deleteItem(item) {
      if (confirm(`Are you sure you want to delete this ${item.source} revenue entry?`)) {
        this.revenueService.deleteRevenue(item.id).subscribe({
